import { type ReactElement, useMemo } from 'react';
import { useIntl } from 'react-intl';

import { CopyIcon } from '@dynatrace/strato-icons';

import { useCopyToClipboard } from '../../../../../../core/utils/useCopyToClipboard.js';
import { COPY_TO_CLIPBOARD_MESSAGES } from '../../../copy-to-clipboard/copy-to-clipboard-messages.js';
import { ChartSeriesAction } from '../../../series-action/ChartSeriesAction.js';
import { LegendItem } from '../types/legend.js';

export const useLegendItemActions = (
  item: LegendItem,
  onLegendItemAction: () => void,
) => {
  const intl = useIntl();
  const [handleCopyToClipboard] = useCopyToClipboard(item.name);

  const defaultActions: ReactElement = useMemo(
    () => (
      <ChartSeriesAction.Item
        key={item.name}
        data-dt-children-name="LegendCopyName"
        onSelect={() => {
          handleCopyToClipboard();
          onLegendItemAction();
        }}
      >
        <ChartSeriesAction.ItemIcon>
          <CopyIcon />
        </ChartSeriesAction.ItemIcon>
        {intl.formatMessage(COPY_TO_CLIPBOARD_MESSAGES.copyActionName)}
      </ChartSeriesAction.Item>
    ),
    [item.name],
  );

  return { intl, defaultActions };
};
